/*
 * fmax() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x, double y)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += fmax(vx, vy);
#else
    double r = fmax(x, y);
    printf("%016llx %016llx %016llx\n",
           (unsigned long long)d2u(x),
           (unsigned long long)d2u(y),
           (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values - NaN/Inf/zero combos (16) --- */
    emit(0.0, 0.0);
    emit(-0.0, 0.0);
    emit(0.0, -0.0);
    emit(-0.0, -0.0);
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN, 1.0 */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN, 1.0 */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -qNaN, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, qNaN */
    emit_u(0x7ff8000000000000ULL, 0x7ff8000000000000ULL);  /* qNaN, qNaN */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x7ff0000000000000ULL);  /* 1.0, +Inf */
    emit_u(0x3ff0000000000000ULL, 0xfff0000000000000ULL);  /* 1.0, -Inf */
    emit_u(0x7ff0000000000000ULL, 0xfff0000000000000ULL);  /* +Inf, -Inf */
    emit_u(0x7ff0000000000000ULL, 0x7ff0000000000000ULL);  /* +Inf, +Inf */
    emit_u(0xfff0000000000000ULL, 0xfff0000000000000ULL);  /* -Inf, -Inf */

    /* --- Section 2: Subnormal (denormal) values (10) --- */
    emit_u(0x0000000000000001ULL, 0x0000000000000000ULL);  /* min positive subnormal, zero */
    emit_u(0x8000000000000001ULL, 0x0000000000000000ULL);  /* min negative subnormal, zero */
    emit_u(0x0000000000000001ULL, 0x8000000000000001ULL);  /* min pos subnorm, min neg subnorm */
    emit_u(0x0008000000000000ULL, 0x0000000000000000ULL);  /* mid positive subnormal, zero */
    emit_u(0x8008000000000000ULL, 0x0000000000000000ULL);  /* mid negative subnormal, zero */
    emit_u(0x000fffffffffffffULL, 0x0000000000000000ULL);  /* max subnormal (just below DBL_MIN), zero */
    emit_u(0x800fffffffffffffULL, 0x0000000000000000ULL);  /* max negative subnormal, zero */
    emit_u(0x000fffffffffffffULL, 0x800fffffffffffffULL);  /* max pos subnorm, max neg subnorm */
    emit_u(0x0008000000000000ULL, 0x8008000000000000ULL);  /* mid pos subnorm, mid neg subnorm */
    emit_u(0x0000000000000001ULL, 0x000fffffffffffffULL);  /* min pos subnorm, max pos subnorm */

    /* --- Section 3: Normal boundary values (8) --- */
    emit(DBL_MIN, 0.0);                                    /* smallest normal, zero */
    emit(-DBL_MIN, 0.0);                                   /* smallest negative normal, zero */
    emit_u(0x0010000000000001ULL, 0x0010000000000000ULL);  /* one ULP above DBL_MIN, DBL_MIN */
    emit(DBL_MIN, -DBL_MIN);                               /* smallest normal, negative counterpart */
    emit(DBL_MAX, 1.0);                                    /* largest normal, one */
    emit(-DBL_MAX, 1.0);                                   /* largest negative normal, one */
    emit(DBL_MAX, -DBL_MAX);                               /* largest pos, largest neg */
    emit_u(0x7fefffffffffffffULL, 0x7feeffffffffffffULL);  /* DBL_MAX, one ULP below DBL_MAX */

    /* --- Section 4: Near 1.0 - ULP density region (10) --- */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 1.0, 1.0 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 1.0, 1.0 */
    emit_u(0x3ff0000000000000ULL, 0xbff0000000000000ULL);  /* 1.0, -1.0 */
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000001ULL);  /* one ULP below 1.0, one ULP above 1.0 */
    emit_u(0xbfefffffffffffffULL, 0xbff0000000000000ULL);  /* one ULP toward zero from -1.0, -1.0 */
    emit_u(0xbff0000000000001ULL, 0xbff0000000000000ULL);  /* one ULP away from zero from -1.0, -1.0 */
    emit(1.0, 1.0);
    emit(-1.0, -1.0);
    emit_u(0x3ff0000000000010ULL, 0x3ff0000000000000ULL);  /* a few ULPs above 1.0, 1.0 */
    emit_u(0x3feffffffffffff0ULL, 0x3ff0000000000000ULL);  /* a few ULPs below 1.0, 1.0 */

    /* --- Section 5: Equal values (8) --- */
    emit(0.5, 0.5);
    emit(-0.5, -0.5);
    emit(2.0, 2.0);
    emit(-2.0, -2.0);
    emit(3.14159265358979, 3.14159265358979);
    emit(1.0e10, 1.0e10);
    emit(1.0e-10, 1.0e-10);
    emit(1.0e100, 1.0e100);

    /* --- Section 6: Positive asymmetric pairs (12) --- */
    emit(1.0, 2.0);
    emit(2.0, 1.0);
    emit(0.5, 1.5);
    emit(1.5, 0.5);
    emit(10.0, 20.0);
    emit(20.0, 10.0);
    emit(100.0, 50.0);
    emit(50.0, 100.0);
    emit(1.0e50, 1.0e100);
    emit(1.0e100, 1.0e50);
    emit(1.0e-10, 1.0e10);
    emit(1.0e10, 1.0e-10);

    /* --- Section 7: Negative asymmetric pairs (10) --- */
    emit(-1.0, -2.0);
    emit(-2.0, -1.0);
    emit(-0.5, -1.5);
    emit(-1.5, -0.5);
    emit(-10.0, -20.0);
    emit(-20.0, -10.0);
    emit(-100.0, -50.0);
    emit(-50.0, -100.0);
    emit(-1.0e50, -1.0e100);
    emit(-1.0e100, -1.0e50);

    /* --- Section 8: Mixed sign pairs (10) --- */
    emit(-1.0, 1.0);
    emit(1.0, -1.0);
    emit(-2.0, 2.0);
    emit(2.0, -2.0);
    emit(-0.5, 0.5);
    emit(0.5, -0.5);
    emit(-1.0e100, 1.0e100);
    emit(1.0e100, -1.0e100);
    emit(-1.0e-300, 1.0e-300);
    emit(1.0e-300, -1.0e-300);

    /* --- Section 9: Large and extreme values (8) --- */
    emit(1.0e300, 1.0e200);
    emit(1.0e200, 1.0e300);
    emit(-1.0e300, 1.0e300);
    emit(1.0e300, -1.0e300);
    emit(1.0e-300, 1.0e-200);
    emit(1.0e-200, 1.0e-300);
    emit(DBL_MAX, DBL_MIN);
    emit(-DBL_MAX, DBL_MIN);

    /* --- Section 10: Exponent sweep pairs (8) --- */
    emit(1.0e-100, 1.0e-50);
    emit(1.0e-50, 1.0e-10);
    emit(1.0e-10, 1.0);
    emit(1.0, 1.0e10);
    emit(1.0e10, 1.0e50);
    emit(1.0e50, 1.0e100);
    emit(1.0e-100, 1.0e100);
    emit(-1.0e-100, -1.0e100);
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
#endif
    return 0;
}

